{
  "grammar": [
    {
      "pattern": "雖然 + A, 但是 + B",
      "structure": ["雖然 + clause A", "但是 + clause B"],
      "explanation_en": "Use '雖然...但是...' to express that although A is true, B is also true, often with a contrasting or unexpected relationship.",
      "title": "雖然...但是... (Although... but...)",
      "meaning": "Although A is true, B is also true (contrast).",
      "when_to_use": [
        "When you want to acknowledge a fact but present a contrasting fact",
        "In conversations about opinions, experiences, or decisions where two things seem contradictory"
      ],
      "when_not_to_use": [
        "Do not use when the two clauses are not in contrast (use '而且' instead)",
        "Avoid using '雖然' alone without a contrastive conjunction like '但是' or '可是'"
      ],
      "pragmatic_notes": "In Taiwan, '雖然...但是...' is very common in daily speech. It's polite to use it when disagreeing gently, e.g., '雖然很好吃，但是太貴了。'",
      "word_order_notes": "The '雖然' clause comes first, followed by the '但是' clause. The subject can be omitted if clear from context.",
      "english_contrast": "English uses 'although... but...' which is redundant; Chinese requires both parts for clarity.",
      "korean_contrast": "Korean uses '비록...지만' similar structure, but Chinese uses two separate clauses with conjunctions.",
      "negative_examples": [
        {
          "text": "雖然他來了，他沒說話。",
          "error": "Missing '但是' or '可是' to show contrast; sounds incomplete."
        }
      ],
      "incorrect_examples": [
        {
          "text": "雖然他來了，但是他沒說話。",
          "error": "Correct structure; no error here."
        }
      ],
      "transformation_drills": [
        "Transform: '他很累，他還是去上班。' → '雖然他很累，但是他還是去上班。'"
      ],
      "production_drills": [
        "Make a sentence: '雖然天氣很冷，但是...' (complete with your own idea)"
      ],
      "common_error_patterns": [
        "Using '雖然' without a contrastive conjunction",
        "Placing '雖然' after the first clause"
      ],
      "repair_feedback": {
        "word_order": "Put '雖然' at the beginning of the first clause.",
        "politeness": "Using '雖然...但是...' is polite for expressing disagreement.",
        "vocabulary": "Use '但是' for formal contrast, '可是' for casual."
      }
    },
    {
      "pattern": "A, 可是 B",
      "structure": ["clause A", "可是 + clause B"],
      "explanation_en": "Use '可是' to connect two clauses where B contrasts with or qualifies A. It's softer than '但是' and common in spoken Taiwanese Mandarin.",
      "title": "可是 (But / However)",
      "meaning": "But / However (soft contrast).",
      "when_to_use": [
        "In casual conversation to show contrast or reservation",
        "When you want to politely disagree or add a different perspective"
      ],
      "when_not_to_use": [
        "Do not use '可是' for strong logical contrast (use '但是' instead)",
        "Avoid using '可是' at the beginning of a sentence in formal writing"
      ],
      "pragmatic_notes": "In Taiwan, '可是' is very common in daily speech. It's often used to soften disagreement, e.g., '我想去，可是沒時間。'",
      "word_order_notes": "'可是' always comes between the two clauses, after the first clause's comma or pause.",
      "english_contrast": "English 'but' can start a sentence; Chinese '可是' usually connects within a sentence.",
      "korean_contrast": "Korean '그런데' is similar but can start a sentence; '可是' is more connective.",
      "negative_examples": [
        {
          "text": "可是我不喜歡，他喜歡。",
          "error": "'可是' at the beginning is awkward; use '但是' or rephrase."
        }
      ],
      "incorrect_examples": [
        {
          "text": "他喜歡，可是我不喜歡。",
          "error": "Correct usage; no error."
        }
      ],
      "transformation_drills": [
        "Transform: '他很忙，他還是來了。' → '他很忙，可是他還是來了。'"
      ],
      "production_drills": [
        "Complete: '我想去夜市，可是...' (give a reason)"
      ],
      "common_error_patterns": [
        "Using '可是' at the start of a sentence in formal contexts",
        "Confusing '可是' with '但是' in strong contrasts"
      ],
      "repair_feedback": {
        "word_order": "Place '可是' after the first clause, before the second.",
        "politeness": "'可是' is polite for gentle contrast.",
        "vocabulary": "Use '可是' for casual, '但是' for formal."
      }
    },
    {
      "pattern": "還是 + verb phrase (still)",
      "structure": ["還是 + verb phrase"],
      "explanation_en": "Use '還是' to mean 'still' or 'nevertheless', indicating that despite a condition, the action or state continues.",
      "title": "還是 (Still / Nevertheless)",
      "meaning": "Still / Nevertheless (despite condition).",
      "when_to_use": [
        "When something continues despite an obstacle or contrary expectation",
        "In concessions: '雖然A，還是B' meaning 'Although A, still B'"
      ],
      "when_not_to_use": [
        "Do not use '還是' for 'or' in questions (use '還是' for 'or' in alternatives, but here it's 'still')",
        "Avoid using '還是' when you mean 'also' (use '也')"
      ],
      "pragmatic_notes": "In Taiwan, '還是' is very common in concessions, e.g., '雖然下雨，我還是要去。' It emphasizes persistence.",
      "word_order_notes": "'還是' comes before the verb phrase, after the subject if present.",
      "english_contrast": "English 'still' can be at the end; Chinese '還是' is always before the verb.",
      "korean_contrast": "Korean '여전히' is similar but often at the beginning; '還是' is before the verb.",
      "negative_examples": [
        {
          "text": "我還是去，雖然下雨。",
          "error": "Word order: '雖然' clause should come first for clarity."
        }
      ],
      "incorrect_examples": [
        {
          "text": "雖然下雨，我還是去。",
          "error": "Correct usage; no error."
        }
      ],
      "transformation_drills": [
        "Transform: '他生病了，他來上課。' → '他生病了，他還是來上課。'"
      ],
      "production_drills": [
        "Make a sentence: '雖然很累，我還是...' (complete with an action)"
      ],
      "common_error_patterns": [
        "Confusing '還是' (still) with '還是' (or) in questions",
        "Placing '還是' at the end of the sentence"
      ],
      "repair_feedback": {
        "word_order": "Put '還是' before the verb, not at the end.",
        "politeness": "Using '還是' shows determination; polite in context.",
        "vocabulary": "Use '還是' for 'still', '也' for 'also'."
      }
    }
  ]
}
